  "type": "DRAG_FILL",
  "data": {
    "challenges": [
      {
        "instruction": "Fill in the blanks using the clues from the earlier content about types of gangs. Refer to the flashcards and the Identifying Types of Gangs Walkthrough.",
        "codeTemplate": "Street Gangs are often involved in local criminal activities and ____ wars. Prison Gangs are formed within ____ systems for protection.",
        "options": [
          "turf",
          "neighborhood",
          "prison",
          "community"
        ],
        "correctAnswer": "turf,prison",
        "explanation": "Street Gangs engage in turf wars, while Prison Gangs are formed within prison systems."
      },
      {
        "instruction": "Using the earlier lesson content, complete the sentence about Motorcycle Gangs. Refer to the flashcards for clues.",
        "codeTemplate": "Motorcycle Gangs are organized groups that often use ____ to enforce their control.",
        "options": [
          "violence",
          "negotiation",
          "community service",
          "law enforcement"
        ],
        "correctAnswer": "violence",
        "explanation": "Motorcycle Gangs typically use violence to enforce their control."
      }
    ]
  }
}
